diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 60da48e1d95d..1490386c4252 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -1359,6 +1359,24 @@ Instruction *InstCombinerImpl::foldICmpWithConstant(ICmpInst &Cmp) {
   if (Instruction *R = tryFoldInstWithCtpopWithNot(&Cmp))
     return R;

+  Value *X;
+  const APInt *SMinC, *SMaxC;
+  if (Pred == ICmpInst::ICMP_EQ && C->isZeroValue() &&
+      match(Op0, m_c_Intrinsic<Intrinsic::smin>(
+                     m_OneUse(m_Intrinsic<Intrinsic::smax>(m_Value(X),
+                                                          m_APInt(SMinC))),
+                     m_APInt(SMaxC)))) {
+    APInt OffsetC = -(*SMinC);
+    APInt RangeC = *SMaxC - *SMinC;
+    if (!OffsetC.isMinSignedValue() && !RangeC.isAllOnes()) {
+      Value *OffsetX =
+          Builder.CreateAdd(X, ConstantInt::get(X->getType(), OffsetC));
+      Value *CmpRange = Builder.CreateICmpULT(
+          OffsetX, ConstantInt::get(X->getType(), RangeC + 1));
+      return replaceInstUsesWith(Cmp, CmpRange);
+    }
+  }
+
   return nullptr;
 }

